package net.honeyberries.discord.slashCommands;

import net.dv8tion.jda.api.JDA;
import net.dv8tion.jda.api.Permission;
import net.dv8tion.jda.api.entities.Guild;
import net.dv8tion.jda.api.entities.channel.concrete.TextChannel;
import net.dv8tion.jda.api.hooks.ListenerAdapter;
import net.dv8tion.jda.api.interactions.commands.DefaultMemberPermissions;
import net.dv8tion.jda.api.events.interaction.command.SlashCommandInteractionEvent;
import net.dv8tion.jda.api.interactions.commands.build.*;
import net.dv8tion.jda.api.interactions.commands.OptionType;
import net.dv8tion.jda.api.requests.restaction.CommandListUpdateAction;
import net.honeyberries.database.GuildRulesRepository;
import net.honeyberries.datatypes.action.GuildRules;
import net.honeyberries.datatypes.discord.GuildID;
import org.jetbrains.annotations.NotNull;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.util.Objects;

public class DebugCommands extends ListenerAdapter {

    private static final Logger logger = LoggerFactory.getLogger(DebugCommands.class);
    private final GuildRulesRepository rulesRepo = GuildRulesRepository.getInstance();


    /**
     * Registers all debug commands with the bot.
     * These commands require administrator permissions.
     */
    public void registerDebugCommands(JDA bot) {
        // 1. Define Subcommands
        SubcommandData refreshSub = new SubcommandData(
                "refresh-rules-and-guidelines",
                "Refreshes the rules and guidelines in the configured channel"
        );

        SubcommandData showSub = new SubcommandData(
                "show-rules-and-guidelines",
                "Shows the current rules and guidelines"
        );

        SubcommandData purgeSub = new SubcommandData("purge", "Deletes and recreates a channel")
                .addOptions(new OptionData(OptionType.CHANNEL, "channel", "Channel to delete and recreate", true));

        // 2. Build the top-level /debug command
        SlashCommandData debugCommand = Commands.slash("debug", "Debug and admin commands")
                .addSubcommands(refreshSub, showSub, purgeSub)
                .setDefaultPermissions(DefaultMemberPermissions.enabledFor(Permission.ADMINISTRATOR));

        // 3. Register with JDA (Global registration)
        bot.updateCommands().addCommands(debugCommand).queue();

        logger.info("Debug commands registered successfully");
    }



    @Override
    public void onSlashCommandInteraction(@NotNull SlashCommandInteractionEvent event) {
        if (!event.isFromGuild()) {
            event.reply("This command can only be used in servers!").setEphemeral(true).queue();
            return;
        }

        // Check if user has administrator permission
        if (event.getMember() != null && !event.getMember().hasPermission(Permission.ADMINISTRATOR)) {
            event.reply("You need administrator permissions to use this command").setEphemeral(true).queue();
            return;
        }

        // Defer the reply once at the start
        event.deferReply().queue();

        try {
            String commandName = event.getSubcommandName();
            switch (Objects.requireNonNull(commandName)) {
                case "refresh-rules-and-guidelines" -> handleRefreshRulesAndGuidelines(event);
                case "show-rules-and-guidelines" -> handleShowRulesAndGuidelines(event);
                case "purge" -> handlePurge(event);

                default -> event.getHook().sendMessage("Unknown command").queue();
            }
        } catch (Exception e) {
            logger.error("Error processing slash command: {}", event.getSubcommandName(), e);
            event.getHook().sendMessage("An error occurred while processing your command").queue();
        }
    }


    /**
     * Refreshes rules and guidelines by posting them to the designated channel.
     */
    private void handleRefreshRulesAndGuidelines(@NotNull SlashCommandInteractionEvent event) {

        try {
            GuildID guildId = new GuildID(event.getGuild().getIdLong());
            GuildRules rules = rulesRepo.getGuildRules(guildId);

            if (rules == null) {
                event.getHook().sendMessage("No rules found for this guild. Please set rules first.").queue();
                return;
            }

            event.getHook().sendMessage("Rules and guidelines refreshed successfully!").queue();
            logger.info("Refreshed rules for guild: {}", guildId.value());
        } catch (Exception e) {
            logger.error("Error refreshing rules and guidelines", e);
            event.getHook().sendMessage("Failed to refresh rules and guidelines").queue();
        }
    }


    /**
     * Shows the current rules and guidelines for the guild.
     */
    private void handleShowRulesAndGuidelines(@NotNull SlashCommandInteractionEvent event) {

        try {
            GuildID guildId = new GuildID(Objects.requireNonNull(event.getGuild()).getIdLong());
            GuildRules rules = rulesRepo.getGuildRules(guildId);

            if (rules == null) {
                event.getHook().sendMessage("No rules found for this guild.").queue();
                return;
            }

            String message = "**Current Guild Rules:**\n\n" +
                    rules.rulesText();

            event.getHook().sendMessage(message).queue();
            logger.info("Showed rules for guild: {}", guildId.value());
        } catch (Exception e) {
            logger.error("Error showing rules and guidelines", e);
            event.getHook().sendMessage("Failed to retrieve rules and guidelines").queue();
        }
    }


    /**
     * Deletes and recreates a channel (purges it).
     */
    private void handlePurge(@NotNull SlashCommandInteractionEvent event) {

        try {
            TextChannel targetChannel = event.getOption("channel", null, option -> 
                    option.getAsChannel().asTextChannel()
            );

            if (targetChannel == null) {
                event.getHook().sendMessage("Please specify a valid text channel").queue();
                return;
            }

            String channelName = targetChannel.getName();
            int position = targetChannel.getPositionRaw();
            String topic = targetChannel.getTopic();

            Guild guild = event.getGuild();

            // Delete the channel
            targetChannel.delete().queue(
                    deleted -> {
                        // Recreate the channel
                        assert guild != null;

                        guild.createTextChannel(channelName)
                                .setPosition(position)
                                .setTopic(topic)
                                .queue(
                                        newChannel -> {
                                            event.getHook().sendMessage("Channel purged successfully! New channel: " + newChannel.getAsMention()).queue();
                                            logger.info("Purged channel: {} in guild: {}", channelName, Objects.requireNonNull(event.getGuild()).getId());
                                        },
                                        throwable -> {
                                            event.getHook().sendMessage("Failed to recreate channel").queue();
                                            logger.error("Failed to recreate channel", throwable);
                                        }
                                );
                    },
                    throwable -> {
                        event.getHook().sendMessage("Failed to delete channel").queue();
                        logger.error("Failed to delete channel", throwable);
                    }
            );
        } catch (Exception e) {
            logger.error("Error purging channel", e);
            event.getHook().sendMessage("Failed to purge channel").queue();
        }
    }

}

package net.honeyberries.discord.slashCommands;

import net.dv8tion.jda.api.JDA;
import net.dv8tion.jda.api.Permission;
import net.dv8tion.jda.api.entities.Guild;
import net.dv8tion.jda.api.entities.channel.concrete.TextChannel;
import net.dv8tion.jda.api.hooks.ListenerAdapter;
import net.dv8tion.jda.api.interactions.commands.DefaultMemberPermissions;
import net.dv8tion.jda.api.events.interaction.command.SlashCommandInteractionEvent;
import net.dv8tion.jda.api.interactions.commands.build.*;
import net.dv8tion.jda.api.interactions.commands.OptionType;
import net.dv8tion.jda.api.requests.restaction.CommandListUpdateAction;
import net.honeyberries.database.GuildRulesRepository;
import net.honeyberries.datatypes.action.GuildRules;
import net.honeyberries.datatypes.discord.GuildID;
import org.jetbrains.annotations.NotNull;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.util.Objects;

public class DebugCommands extends ListenerAdapter {

    private static final Logger logger = LoggerFactory.getLogger(DebugCommands.class);
    private final GuildRulesRepository rulesRepo = GuildRulesRepository.getInstance();


    /**
     * Registers all debug commands with the bot.
     * These commands require administrator permissions.
     */
    public void registerDebugCommands(JDA bot) {
        // 1. Define Subcommands
        SubcommandData refreshSub = new SubcommandData(
                "refresh-rules-and-guidelines",
                "Refreshes the rules and guidelines in the configured channel"
        );

        SubcommandData showSub = new SubcommandData(
                "show-rules-and-guidelines",
                "Shows the current rules and guidelines"
        );

        SubcommandData purgeSub = new SubcommandData("purge", "Deletes and recreates a channel")
