import net.dv8tion.jda.api.interactions.commands.build.SlashCommandData;
import net.dv8tion.jda.api.interactions.commands.build.SubcommandData;
import net.dv8tion.jda.api.requests.restaction.CommandListUpdateAction;
import net.honeyberries.database.SpecialUsersRepository;
import net.honeyberries.util.PreferenceCommandHelper;
import org.jetbrains.annotations.NotNull;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.util.Objects;

/**
 * Slash command handler for guild preference management.
 *
 * <p>Provides administrators with tools to configure guild-specific bot settings 
 * and preferences. Supports enabling/disabling AI, setting rules and audit channels,
 * and viewing current settings. Preferences control bot behavior specific to each guild.
 */
public class PreferencesCommands extends ListenerAdapter {

    private static final Logger logger = LoggerFactory.getLogger(PreferencesCommands.class);
    private final PreferenceCommandHelper helper = new PreferenceCommandHelper();


    /**
     * Registers the `/preferences` slash command with multiple subcommands for managing
     * guild preferences and settings.
     * <p>
     * The available subcommands include:
     * - `enable_ai`: Enable or disable AI moderation or view the current setting.
     * - `set_rules_channel`: Set the rules channel for the guild or view the current channel.
     * - `set_audit_channel`: Set the audit log channel for the guild or view the current channel.
     * - `settings`: View and manage guild preferences through a graphical interface.
     * - `reset`: Reset all preferences to their default values.
     * - `action`: Enable or disable specific moderation actions or view all available actions.
     * <p>
     * Each subcommand may include specific options to allow flexibility in usage.
     *
     * @param commands The {@link CommandListUpdateAction} instance used to register slash commands.
     *                 Must not be null.
     * @throws NullPointerException if the {@code commands} parameter is null.
     */
    public void registerPreferencesCommands(@NotNull CommandListUpdateAction commands) {
        Objects.requireNonNull(commands, "commands must not be null");

        SubcommandData enableAiSub = new SubcommandData(
                "enable_ai",
                "Enable or disable AI moderation (or view current setting)"
        ).addOptions(
                new OptionData(OptionType.BOOLEAN, "enabled", "Enable or disable AI (leave empty to view current)", false)
        );

        SubcommandData setRulesChannelSub = new SubcommandData(
                "set_rules_channel",
                "Set the rules channel for this guild (or view current channel)"
        ).addOptions(
                new OptionData(OptionType.CHANNEL, "channel", "Channel for rules (leave empty to view current)", false)
        );

        SubcommandData setAuditChannelSub = new SubcommandData(
                "set_audit_channel",
                "Set the audit log channel for this guild (or view current channel)"
        ).addOptions(
                new OptionData(OptionType.CHANNEL, "channel", "Channel for audit logs (leave empty to view current)", false)
        );

        SubcommandData settingsSub = new SubcommandData(
                "settings",
                "View and manage guild preferences with a graphical interface"
        );

        SubcommandData resetSub = new SubcommandData(
                "reset",
                "Reset all preferences to their default values"
        );

        SubcommandData actionSub = new SubcommandData(
                "action",
                "Enable or disable a specific moderation action (or view all actions)"
        ).addOptions(
                new OptionData(OptionType.STRING, "action", "The moderation action to toggle (leave empty to view all)", false)
                        .addChoice("warn", "warn")
                        .addChoice("timeout", "timeout")
                        .addChoice("delete", "delete")
                        .addChoice("kick", "kick")
                        .addChoice("ban", "ban"),
                new OptionData(OptionType.BOOLEAN, "enabled", "Enable or disable this action (leave empty to view current)", false)
        );

        SlashCommandData preferencesCommand = Commands.slash(
                "preferences",
                "Manage guild preferences and settings"
        ).addSubcommands(enableAiSub, setRulesChannelSub, setAuditChannelSub, settingsSub, resetSub, actionSub);

        Objects.requireNonNull(commands.addCommands(preferencesCommand));
        logger.info("Registered /preferences command with subcommands");
    }

    /**
     * Handles slash command interactions for the preferences command.
     *
     * <p>Routes to the appropriate subcommand handler (enable_ai, set_rules_channel,
     * set_audit_channel, or settings) after validating that the event is from a guild
     * and the invoker has administrator permissions.
     *
     * @param event the slash command interaction event. Must not be null.
     * @throws NullPointerException if event is null
     */
    @Override
    public void onSlashCommandInteraction(@NotNull SlashCommandInteractionEvent event) {
        Objects.requireNonNull(event, "event must not be null");
        if (!event.getName().equals("preferences")) {
            return;
        }

        // Guard: validate guild and permissions before processing
        Guild guild = validateGuildAndPermissions(event);
        if (guild == null) {
            return;
        }

        String subcommand = event.getSubcommandName();
        if (subcommand == null) {
            event.reply("Please specify a subcommand.").setEphemeral(true).queue();
            return;
        }

        try {
            switch (subcommand) {
                case "enable_ai" -> handleEnableAi(event, guild);
                case "set_rules_channel" -> handleSetRulesChannel(event, guild);
                case "set_audit_channel" -> handleSetAuditChannel(event, guild);
                case "settings" -> handleSettings(event);
                case "reset" -> handleReset(event, guild);
                case "action" -> handleAction(event, guild);
                default -> event.reply("Unknown subcommand").setEphemeral(true).queue();
            }
        } catch (Exception e) {
            logger.error("Error handling /preferences {}", subcommand, e);
            event.reply("An unexpected error occurred while processing the command.").setEphemeral(true).queue();
        }
    }


}

package net.honeyberries.services;

import com.fasterxml.jackson.core.JsonProcessingException;
import com.openai.models.ResponseFormatJsonSchema;
import com.openai.models.chat.completions.ChatCompletionMessageParam;
import net.dv8tion.jda.api.entities.Guild;
import net.dv8tion.jda.api.entities.Member;
import net.dv8tion.jda.api.entities.Message;
import net.dv8tion.jda.api.entities.channel.Channel;
import net.honeyberries.ai.*;
import net.honeyberries.datatypes.action.ActionData;
import net.honeyberries.datatypes.content.GuildModerationBatch;
import net.honeyberries.datatypes.content.ModerationMessage;
import net.honeyberries.datatypes.content.ModerationUser;
import net.honeyberries.datatypes.content.ModerationUserChannel;
import net.honeyberries.datatypes.discord.ChannelID;
import net.honeyberries.datatypes.discord.GuildID;
import net.honeyberries.datatypes.discord.MessageID;
import net.honeyberries.datatypes.discord.UserID;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.util.*;
import java.util.concurrent.ExecutionException;
import java.util.stream.Collectors;

public class GlobalProcessingService {

    private final Logger logger = LoggerFactory.getLogger(GlobalProcessingService.class);

    private static final GlobalProcessingService INSTANCE = new GlobalProcessingService();
    private final Map<GuildID, GuildMessageMap> guildQueues;

    private GlobalProcessingService() {
        this.guildQueues = new HashMap<>();
    }

    public static GlobalProcessingService getInstance() {
        return INSTANCE;
    }

    public void addMessage(Guild guild, Message message, boolean isHistory) {
        GuildID guildId = GuildID.fromGuild(guild);

        ModerationMessage moderationMessage = ModerationMessage.fromMessage(message, isHistory);

        guildQueues.computeIfAbsent(guildId, id -> new GuildMessageMap()).addMessage(moderationMessage);
        logger.debug("Added message {} to guild {}", moderationMessage.messageId(), guildId);

    }

    public void updateMessage(Guild guild, Message message, boolean isHistory) {
        GuildID guildId = GuildID.fromGuild(guild);

        ModerationMessage moderationMessage = ModerationMessage.fromMessage(message, isHistory);
        MessageID messageId = moderationMessage.messageId();

        guildQueues.computeIfAbsent(guildId,
                id -> new GuildMessageMap()).replaceMessage(messageId, moderationMessage);

        logger.debug("Updated message {} in guild {}", messageId, guildId);
    }


    public void removeMessage(Guild guild, MessageID messageID) {
        GuildID guildId = GuildID.fromGuild(guild);
        guildQueues.computeIfAbsent(guildId, id -> new GuildMessageMap()).removeMessage(messageID);
        logger.debug("Removed message {} from guild {}", messageID, guildId);
    }


    public List<ActionData> getActionDataFromAI(GuildMessageMap guildMessageMap, Guild guild) {
        GuildID guildId = GuildID.fromGuild(guild);

        List<ModerationUser> users = buildModerationUsers(guildMessageMap.getCurrentMessages(), guild);
        List<ModerationUser> historyUsers = buildModerationUsers(guildMessageMap.getHistoryContextMessages(), guild);

        GuildModerationBatch batch = new GuildModerationBatch(
                guildId,
                guild.getName(),
                Map.of(),
                users,
                historyUsers
        );

        ChatCompletionMessageParam inputs;
        ChatCompletionMessageParam systemPrompt;
        ResponseFormatJsonSchema schema;
        String response;

        try {
            inputs = GuildModerationBatchToAIInput.createMessageFromGuildModerationBatch(batch);
        } catch (GuildModerationBatchToAIInput.GuildModerationBatchSerializationException e) {
            logger.error("Failed to serialize guild moderation batch for guild {}", guildId, e);
            return List.of();
        }

        try {
            schema = DynamicSchemaGenerator.getInstance().createDynamicOutputSchema(batch);
        } catch (DynamicSchemaGenerator.DynamicSchemaGeneratorParseException e) {
            logger.error("Failed to generate dynamic schema for guild {}", guildId, e);
            return List.of();
        }

        try {
            systemPrompt = DynamicSystemPrompt.getInstance().createDynamicSystemPrompt(guildId);
        } catch (Exception e) {
            logger.error("Failed to generate dynamic system prompt for guild {}", guildId, e);
            return List.of();
        }

        try {
            response = InferenceEngine.getInstance().generateResponse(List.of(systemPrompt, inputs), schema).get();
        } catch (ExecutionException | InterruptedException e) {
            logger.error("Failed to generate response for guild {}", guildId, e);
            return List.of();
        }

        List<ActionData> actionDataList;

        try {
            actionDataList = ActionDataJSONParser.getInstance().parse(response, guildId);
        } catch (JsonProcessingException e) {
            logger.error("Failed to parse AI response for guild {}", guildId, e);
            return List.of();
        }

        return actionDataList;
    }

    private List<ModerationUser> buildModerationUsers(List<ModerationMessage> messages, Guild guild) {
        Map<UserID, Map<ChannelID, List<ModerationMessage>>> userChannelMap = new HashMap<>();
        for (ModerationMessage msg : messages) {
            userChannelMap
                    .computeIfAbsent(msg.userId(), k -> new HashMap<>())
                    .computeIfAbsent(msg.channelId(), k -> new ArrayList<>())
                    .add(msg);
        }

        List<ModerationUser> result = new ArrayList<>();
        for (Map.Entry<UserID, Map<ChannelID, List<ModerationMessage>>> userEntry : userChannelMap.entrySet()) {
            UserID userId = userEntry.getKey();

            Member member = guild.getMemberById(userId.value());
            if (member == null) continue;

            List<ModerationUserChannel> channels = new ArrayList<>();
            for (Map.Entry<ChannelID, List<ModerationMessage>> channelEntry : userEntry.getValue().entrySet()) {
                ChannelID channelId = channelEntry.getKey();
                Channel channel = guild.getGuildChannelById(channelId.value());
                String channelName = channel != null ? channel.getName() : "Unknown";
                channels.add(new ModerationUserChannel(userId, channelId, channelName, channelEntry.getValue()));
            }

            List<String> roles = member.getRoles().stream()
                    .map(net.dv8tion.jda.api.entities.Role::getName)
                    .collect(Collectors.toList());

            result.add(new ModerationUser(
                    userId,
                    new net.honeyberries.datatypes.discord.DiscordUsername(userId, member.getEffectiveName()),
                    member.getTimeJoined().toLocalDateTime(),
                    member,
                    guild,
                    roles,
                    channels
            ));
        }
        return result;
    }


    public boolean processActions(List<ActionData> actions) {
        //TODO: Implement the actual processing of actions, including applying them to the guild and handling any errors.
        return false;
    }


}

