-- ========================== -- Table: guild_moderation_action_deletions -- ========================== CREATE TABLE IF NOT EXISTS guild_moderation_action_deletions ( action_id BIGINT NOT NULL, -- FK to guild_moderation_actions.id channel_id BIGINT NOT NULL, message_id BIGINT NOT NULL, PRIMARY KEY (action_id, channel_id, message_id), CONSTRAINT fk_action FOREIGN KEY (action_id) REFERENCES guild_moderation_actions(id) ON DELETE CASCADE );
-- ========================== -- Trigger Function (reusable) -- ========================== CREATE OR REPLACE FUNCTION fn_update_timestamp() RETURNS TRIGGER AS $$ BEGIN NEW.updated_at = CURRENT_TIMESTAMP; RETURN NEW; END; $$ LANGUAGE plpgsql;
-- ========================== -- Triggers for automatic updated_at -- ========================== CREATE TRIGGER trg_guild_preferences_update BEFORE UPDATE ON guild_preferences FOR EACH ROW EXECUTE FUNCTION fn_update_timestamp();
CREATE TRIGGER trg_guild_channel_guidelines_update BEFORE UPDATE ON guild_channel_guidelines FOR EACH ROW EXECUTE FUNCTION fn_update_timestamp();
CREATE TRIGGER trg_guild_rules_update BEFORE UPDATE ON guild_rules FOR EACH ROW EXECUTE FUNCTION fn_update_timestamp();
CREATE TRIGGER trg_guild_moderation_actions_update BEFORE UPDATE ON guild_moderation_actions FOR EACH ROW EXECUTE FUNCTION fn_update_timestamp();
